// Parse the JSON Claude returned and compute pricing/margin.
const raw = $json.content?.[0]?.text || '{}';
let product;
try {
  const match = raw.match(/\{[\s\S]*\}/);
  product = JSON.parse(match ? match[0] : raw);
} catch (e) {
  throw new Error('Could not parse AI product JSON: ' + raw);
}

// --- Your pricing rule: markup + floor ---
const supplier = Number(product.supplier_price) || 0;
const MARKUP = 3.0;        // sell at 3x supplier cost
const MIN_MARGIN = 12;     // never sell for less than $12 over cost
let price = Math.max(supplier * MARKUP, supplier + MIN_MARGIN);
price = Math.max(price, 9.99);
price = Math.round(price) - 0.01; // charm pricing e.g. 29.99

return [{ json: { ...product, supplier_price: supplier, sell_price: price } }];

