// carry the product data forward too
const product = $('Compute Price + Margin').item.json;
return [{ json: { ...product, ...copy } }];

// Build one item per image URL so we can attach them to the Shopify product.
const product = $('Merge Copy + Product').item.json;
const productId = $json.id;
const urls = (product.image_urls || []).filter(Boolean).slice(0, 5);
